import sys
import typing

class Solution:
    def coinChange(self, coins: typing.List[int], amount: int) -> int:
        dp = [-1] * (amount + 1)
        dp[0] = 0
        for i in range(1, amount + 1):
            for coin in coins:
                if i >= coin:
                    dp[i] = min(dp[i], 1 + dp[i - coin])
        return dp[amount] if dp[amount] != -1 else -1

if __name__ == '__main__':
    solution = Solution()
    input_str = sys.stdin.readline().strip()
    n = int(input_str)
    input_str = sys.stdin.readline().strip()
    coins = list(map(int, input_str.split()))
    amount = int(sys.stdin.readline().strip())
    print(solution.coinChange(coins, amount))

